const base = (() => {
  try {
    return $item(0).$node['Session Bootstrap'].json ?? {};
  } catch {
    return {};
  }
})();
const payload = $json ?? {};
const event = base.event && typeof base.event === 'object' ? base.event : {};
const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};
const issues = [];

const parseJsonObject = (value) => {
  if (!value) return null;
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value !== 'string' || !value.trim()) return null;
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
};

const rawResponse = parseJsonObject(payload.choices?.[0]?.message?.content)
  || parseJsonObject(payload.output_text)
  || parseJsonObject(payload.text)
  || parseJsonObject(payload.data)
  || parseJsonObject(payload.result)
  || parseJsonObject(payload);
if (!rawResponse) {
  issues.push('understanding_response_not_parseable');
}

const text = String(event.text ?? '').trim();
const lower = text.toLowerCase();
const hasAny = (tokens) => tokens.some((token) => lower.includes(token));
const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const toStringArray = (value) => Array.isArray(value)
  ? value.filter((item) => typeof item === 'string').map((item) => item.trim()).filter(Boolean)
  : [];
const normalizeEnum = (value, allowed, synonyms, label) => {
  if (value === null && allowed.includes(null)) return null;
  if (typeof value === 'string') {
    const normalized = synonyms[String(value).trim().toLowerCase()] ?? String(value).trim().toLowerCase();
    if (allowed.includes(normalized)) return normalized;
    issues.push(label + '_invalid:' + value);
  }
  return undefined;
};

const greetingSignal = hasAny(['selam', 'hello', 'hi', 'hey', 'good morning', 'good evening']);
const acknowledgmentSignal = hasAny(['ok', 'okay', 'thanks', 'thank you', 'got it', 'noted']);
const offTopicSignal = hasAny(['weather', 'football', 'soccer', 'movie', 'music', 'joke', 'news', 'time', 'sleep']);
const pricingSignal = hasAny(['price', 'how much', 'cost', 'budget', 'last price']);
const stockSignal = hasAny(['available', 'availability', 'in stock', 'stock']);
const exchangeSignal = hasAny(['exchange', 'swap', 'trade', 'trade in']);
const supportSignal = hasAny(['problem', 'issue', 'complaint', 'support', 'help']);
const infoSignal = hasAny(['where', 'location', 'address', 'shop', 'store', 'hours', 'payment', 'warranty', 'delivery', 'policy']);
const productSignal = hasAny(['phone', 'iphone', 'samsung', 'tecno', 'infinix', 'redmi', 'xiaomi', 'pixel', 'model', 'slk', 'buy', 'want']);
const humorousSignal = hasAny(['haha', 'lol', 'lmao']);
const urgentSignal = hasAny(['urgent', 'asap', 'quick', 'immediately']);
const formalSignal = hasAny(['please', 'kindly']);
const negativeSignal = hasAny(['bad', 'terrible', 'angry', 'annoyed']);
const frustratedSignal = hasAny(['frustrated', 'upset', 'fed up']) || (negativeSignal && supportSignal);

const legacyFieldSignals = rawResponse && typeof rawResponse === 'object' && (
  Object.prototype.hasOwnProperty.call(rawResponse, 'user_need')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'next_action')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'tentative_flow')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'ambiguity')
  || Object.prototype.hasOwnProperty.call(rawResponse, 'evidence_accumulated')
);
if (legacyFieldSignals) {
  issues.push('legacy_understanding_fields_detected');
}

const productMatches = [...text.matchAll(/\b(iphone\s*\d+(?:\s*(?:pro|max|plus|mini))?|samsung\s*[a-z0-9+ ]+|tecno\s*[a-z0-9+ ]+|infinix\s*[a-z0-9+ ]+|redmi\s*[a-z0-9+ ]+|xiaomi\s*[a-z0-9+ ]+)\b/gi)]
  .map((match) => match[1].trim())
  .filter(Boolean);
const priceMatches = [...text.matchAll(/(?:\$\s*\d+(?:\.\d+)?)|(?:\b\d{3,6}\s*(?:birr|etb)\b)|(?:\b\d+[kK]\b)/g)]
  .map((match) => match[0].trim())
  .filter(Boolean);
const conditionMatches = [...text.matchAll(/\b(new|used|sealed|clean|condition)\b/gi)]
  .map((match) => match[1].trim().toLowerCase())
  .filter(Boolean);
const ambiguousReferences = [];
for (const pattern of ['that one', 'the one', 'cheaper one', 'cheapest', 'first one', 'last one', 'same one', 'this one']) {
  if (lower.includes(pattern)) ambiguousReferences.push(pattern);
}

const classification = normalizeEnum(rawResponse?.message_classification, ['business', 'off_topic', 'small_talk', 'acknowledgment'], {
  greeting: 'small_talk', greet: 'small_talk', hello: 'small_talk', ack: 'acknowledgment', acknowledgement: 'acknowledgment', offtopic: 'off_topic', 'off-topic': 'off_topic', question: 'business',
}, 'message_classification');
const businessTopic = normalizeEnum(rawResponse?.business_topic, ['product_search', 'pricing', 'stock_check', 'exchange', 'support', 'info_request', null], {
  search: 'product_search', product: 'product_search', buy: 'product_search', price: 'pricing', pricing_request: 'pricing', stock: 'stock_check', availability: 'stock_check', exchange_inquiry: 'exchange', info: 'info_request', shop_info: 'info_request', faq: 'info_request', none: null, onboarding: null,
}, 'business_topic');
const sentiment = normalizeEnum(rawResponse?.sentiment, ['positive', 'neutral', 'negative', 'playful', 'frustrated'], { upset: 'frustrated', angry: 'frustrated', happy: 'positive', joking: 'playful' }, 'sentiment');
const tone = normalizeEnum(rawResponse?.tone, ['casual', 'formal', 'urgent', 'humorous'], { playful: 'humorous', friendly: 'casual' }, 'tone');

const inferredClassification = acknowledgmentSignal ? 'acknowledgment' : offTopicSignal ? 'off_topic' : (greetingSignal && !productSignal && !pricingSignal && !stockSignal && !exchangeSignal && !infoSignal) ? 'small_talk' : (pricingSignal || stockSignal || exchangeSignal || supportSignal || infoSignal || productSignal) ? 'business' : 'small_talk';
let inferredBusinessTopic = null;
if (pricingSignal) inferredBusinessTopic = 'pricing';
else if (stockSignal) inferredBusinessTopic = 'stock_check';
else if (exchangeSignal || rawResponse?.user_need === 'exchange_inquiry') inferredBusinessTopic = 'exchange';
else if (supportSignal || rawResponse?.tentative_flow === 'support') inferredBusinessTopic = 'support';
else if (infoSignal || rawResponse?.tentative_flow === 'faq' || rawResponse?.user_need === 'info_request') inferredBusinessTopic = 'info_request';
else if (productSignal || productMatches.length > 0 || rawResponse?.user_need === 'recommendation' || rawResponse?.user_need === 'transaction') inferredBusinessTopic = 'product_search';

const confidenceSource = Number(rawResponse?.confidence);
let confidence = Number.isFinite(confidenceSource) ? clamp(confidenceSource, 0, 1) : (inferredClassification === 'acknowledgment' ? 0.97 : inferredClassification === 'small_talk' ? 0.92 : inferredClassification === 'off_topic' ? 0.9 : inferredBusinessTopic ? 0.82 : 0.45);
if (String(rawResponse?.ambiguity ?? '').toLowerCase() === 'high') confidence = clamp(confidence - 0.25, 0, 1);

const understanding_output = {
  message_classification: classification ?? inferredClassification,
  business_topic: classification === 'business' || inferredClassification === 'business' ? (businessTopic !== undefined ? businessTopic : inferredBusinessTopic) : (businessTopic === undefined ? null : businessTopic),
  sentiment: sentiment ?? (frustratedSignal ? 'frustrated' : humorousSignal ? 'playful' : negativeSignal ? 'negative' : 'neutral'),
  tone: tone ?? (urgentSignal ? 'urgent' : humorousSignal ? 'humorous' : formalSignal ? 'formal' : 'casual'),
  entities_detected: {
    product_mentions: (() => { const values = toStringArray(rawResponse?.entities_detected?.product_mentions); return values.length > 0 ? values : productMatches.slice(0, 4); })(),
    price_mentions: (() => { const values = toStringArray(rawResponse?.entities_detected?.price_mentions); return values.length > 0 ? values : priceMatches.slice(0, 4); })(),
    condition_mentions: (() => { const values = toStringArray(rawResponse?.entities_detected?.condition_mentions).map((item) => item.toLowerCase()); return values.length > 0 ? values : conditionMatches.slice(0, 4); })(),
    ambiguous_references: (() => { const values = toStringArray(rawResponse?.entities_detected?.ambiguous_references).map((item) => item.toLowerCase()); return values.length > 0 ? values : ambiguousReferences.slice(0, 4); })(),
  },
  extracted_need: typeof rawResponse?.extracted_need === 'string' && rawResponse.extracted_need.trim() ? rawResponse.extracted_need.trim() : (text || 'empty_message'),
  confidence,
  reasoning: typeof rawResponse?.reasoning === 'string' && rawResponse.reasoning.trim() ? rawResponse.reasoning.trim() : 'guard_inferred_from_runtime_context',
};

return [{
  json: {
    event,
    session,
    client_config,
    understanding_output,
    understanding_meta: {
      valid: issues.length === 0,
      issues,
      parsed_source: rawResponse,
      timestamp: Date.now(),
    },
  },
}];

const input = $json ?? {};
const event = input.event && typeof input.event === 'object' ? input.event : {};
const session = input.session && typeof input.session === 'object' ? input.session : {};
const client_config = input.client_config && typeof input.client_config === 'object' ? input.client_config : {};
const understanding_output = input.understanding_output && typeof input.understanding_output === 'object' ? input.understanding_output : {};
const understanding_meta = input.understanding_meta && typeof input.understanding_meta === 'object' ? input.understanding_meta : {};
const text = String(event.text ?? '').trim();
const ambiguousReferences = Array.isArray(understanding_output.entities_detected?.ambiguous_references)
  ? understanding_output.entities_detected.ambiguous_references.filter((item) => typeof item === 'string' && item.trim())
  : [];
const shownProductsRaw = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products
  : [];
const currentInterest = session.flow_context?.buy_flow?.current_interest ?? null;
const currentFlow = session.conversation_state?.current_flow ?? null;

const normalizeProduct = (value, index) => {
  if (value === null || value === undefined) return null;
  if (typeof value === 'string' || typeof value === 'number') return { id: String(value), name: null, price: null, raw: value, index };
  if (typeof value !== 'object') return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  return {
    id: String(value.id ?? value.product_id ?? value.sku ?? ('option_' + index)),
    name: [value.brand, value.model].filter(Boolean).join(' ').trim() || value.name || value.title || null,
    price: Number.isFinite(Number(priceValue)) ? Number(priceValue) : null,
    raw: value,
    index,
  };
};
const shownProducts = shownProductsRaw.map(normalizeProduct).filter(Boolean);

const resolveAmbiguousReference = () => {
  if (ambiguousReferences.length === 0) return { confidence: 0, resolved_reference: null, resolved_product_name: null, ambiguous_reference: null };
  const label = ambiguousReferences[0].toLowerCase();
  const byCheapest = [...shownProducts].filter((item) => item.price !== null).sort((a, b) => a.price - b.price)[0] ?? null;
  const byLast = shownProducts[shownProducts.length - 1] ?? normalizeProduct(currentInterest, shownProducts.length + 1);
  const byFirst = shownProducts[0] ?? null;
  let chosen = null;
  if (label.includes('cheaper') || label.includes('cheapest')) chosen = byCheapest;
  else if (label.includes('first')) chosen = byFirst;
  else if (label.includes('last')) chosen = byLast;
  else if (label.includes('that one') || label.includes('the one') || label.includes('this one') || label.includes('same one')) chosen = normalizeProduct(currentInterest, shownProducts.length + 2) ?? byLast;
  return { confidence: chosen ? 0.85 : 0.35, resolved_reference: chosen ? { id: chosen.id, raw: chosen.raw } : null, resolved_product_name: chosen?.name ?? null, ambiguous_reference: label };
};
const inferFlow = () => {
  const topic = understanding_output.business_topic ?? null;
  if (topic === 'exchange') return 'exchange';
  if (topic === 'info_request') return 'info';
  if (topic === 'support') return 'support';
  if (topic === 'product_search' || topic === 'pricing' || topic === 'stock_check') return 'buy';
  return null;
};

const referenceResolution = resolveAmbiguousReference();
const inferredFlow = inferFlow();
const productMentions = Array.isArray(understanding_output.entities_detected?.product_mentions)
  ? understanding_output.entities_detected.product_mentions.filter((item) => typeof item === 'string' && item.trim())
  : [];

let rules_output = {
  reply_mode: 'small_talk_redirect',
  should_call_resolver: false,
  resolver_input: { flow: null, product_context: null, missing_fields: [], resolved_reference: null, resolved_product_name: null },
  session_update: {
    last_topic: understanding_output.business_topic ?? understanding_output.message_classification ?? null,
    flow_stage: currentFlow,
    ambiguous_reference: referenceResolution.ambiguous_reference,
    resolved_ambiguity: Boolean(referenceResolution.resolved_reference),
  },
  confidence: typeof understanding_output.confidence === 'number' ? understanding_output.confidence : 0,
  reasoning: 'default_small_talk_redirect',
};

const classification = understanding_output.message_classification ?? 'small_talk';
const sentiment = understanding_output.sentiment ?? 'neutral';

if (event.event_type === 'start_reset') {
  rules_output = { ...rules_output, reply_mode: 'small_talk_redirect', should_call_resolver: false, reasoning: 'start_reset_welcome', session_update: { ...rules_output.session_update, last_topic: null, flow_stage: null, ambiguous_reference: null, resolved_ambiguity: false } };
} else if (event.event_type === 'deep_link_start') {
  rules_output = { ...rules_output, reply_mode: 'business_resolve', should_call_resolver: true, resolver_input: { flow: 'buy', product_context: text || null, missing_fields: [], resolved_reference: null, resolved_product_name: productMentions[0] ?? null }, session_update: { ...rules_output.session_update, last_topic: 'product_search', flow_stage: 'buy' }, reasoning: 'deep_link_start_business_entry' };
} else if (typeof understanding_output.confidence !== 'number' || understanding_output.confidence < 0.6) {
  rules_output = { ...rules_output, reply_mode: 'handoff_admin', should_call_resolver: false, reasoning: 'low_understanding_confidence' };
} else if (classification === 'acknowledgment') {
  rules_output = { ...rules_output, reply_mode: 'acknowledge_and_close', should_call_resolver: false, reasoning: 'acknowledgment_detected' };
} else if (classification === 'small_talk' || classification === 'off_topic') {
  const reply_mode = sentiment === 'frustrated' ? 'handoff_admin' : ((sentiment === 'playful' || understanding_output.tone === 'humorous') ? 'small_talk_redirect' : (classification === 'small_talk' ? 'small_talk_redirect' : 'off_topic_redirect'));
  rules_output = { ...rules_output, reply_mode, should_call_resolver: false, reasoning: classification + '_handled_without_resolver' };
} else if (classification === 'business') {
  const productContext = productMentions[0] ?? currentInterest ?? null;
  const missingFields = inferredFlow === 'buy' && !productContext && !referenceResolution.resolved_reference ? ['product_context'] : [];
  if (ambiguousReferences.length > 0) {
    if (referenceResolution.confidence >= 0.8) {
      rules_output = { ...rules_output, reply_mode: 'business_resolve', should_call_resolver: true, resolver_input: { flow: inferredFlow, product_context: productContext, missing_fields: missingFields, resolved_reference: referenceResolution.resolved_reference, resolved_product_name: referenceResolution.resolved_product_name }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow, ambiguous_reference: referenceResolution.ambiguous_reference, resolved_ambiguity: true }, reasoning: 'ambiguous_reference_resolved_from_session' };
    } else {
      rules_output = { ...rules_output, reply_mode: 'clarify_reference', should_call_resolver: false, resolver_input: { ...rules_output.resolver_input, flow: inferredFlow, product_context: productContext }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow, ambiguous_reference: referenceResolution.ambiguous_reference, resolved_ambiguity: false }, reasoning: 'ambiguous_reference_needs_clarification' };
    }
  } else if (inferredFlow && currentFlow && inferredFlow === currentFlow) {
    rules_output = { ...rules_output, reply_mode: 'resume_previous_flow', should_call_resolver: true, resolver_input: { flow: inferredFlow, product_context: productContext, missing_fields: missingFields, resolved_reference: null, resolved_product_name: productMentions[0] ?? null }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow }, reasoning: 'continues_existing_flow' };
  } else {
    rules_output = { ...rules_output, reply_mode: 'business_resolve', should_call_resolver: true, resolver_input: { flow: inferredFlow, product_context: productContext, missing_fields: missingFields, resolved_reference: null, resolved_product_name: productMentions[0] ?? null }, session_update: { ...rules_output.session_update, flow_stage: inferredFlow }, reasoning: 'business_request_ready_for_resolver' };
  }
}

return [{ json: { event, session, client_config, understanding_output, understanding_meta, rules_output } }];

const input = $json ?? {};
const event = input.event && typeof input.event === 'object' ? input.event : {};
const session = input.session && typeof input.session === 'object' ? input.session : {};
const client_config = input.client_config && typeof input.client_config === 'object' ? input.client_config : {};
const understanding_output = input.understanding_output && typeof input.understanding_output === 'object' ? input.understanding_output : {};
const rules_output = input.rules_output && typeof input.rules_output === 'object' ? input.rules_output : {};
const resolverInput = rules_output.resolver_input && typeof rules_output.resolver_input === 'object' ? rules_output.resolver_input : {};

const normalizeProduct = (value, index) => {
  if (value === null || value === undefined) return null;
  if (typeof value === 'string' || typeof value === 'number') {
    return { id: String(value), brand: null, model: null, price_etb: null, storage: null, condition: null, stock_status: null };
  }
  if (typeof value !== 'object') return null;
  const priceValue = value.price_etb ?? value.price ?? value.amount ?? null;
  return {
    id: String(value.id ?? value.product_id ?? value.sku ?? ('product_' + index)),
    brand: value.brand ?? null,
    model: value.model ?? value.name ?? value.title ?? null,
    price_etb: Number.isFinite(Number(priceValue)) ? Number(priceValue) : null,
    storage: value.storage ?? null,
    condition: value.condition ?? null,
    stock_status: value.stock_status ?? null,
  };
};

const shownProducts = Array.isArray(session.flow_context?.buy_flow?.shown_products)
  ? session.flow_context.buy_flow.shown_products.map(normalizeProduct).filter(Boolean)
  : [];
const currentInterest = normalizeProduct(session.flow_context?.buy_flow?.current_interest, shownProducts.length + 10);
const requestedName = typeof resolverInput.resolved_product_name === 'string' && resolverInput.resolved_product_name.trim()
  ? resolverInput.resolved_product_name.trim().toLowerCase()
  : null;
let selectedProduct = null;
if (resolverInput.resolved_reference?.id) {
  selectedProduct = shownProducts.find((product) => product.id === resolverInput.resolved_reference.id) ?? null;
}
if (!selectedProduct && requestedName) {
  selectedProduct = shownProducts.find((product) => {
    const name = [product.brand, product.model].filter(Boolean).join(' ').trim().toLowerCase();
    return Boolean(name) && name === requestedName;
  }) ?? null;
}
if (!selectedProduct && currentInterest) {
  selectedProduct = currentInterest;
}

const products = selectedProduct ? [selectedProduct] : shownProducts.slice(0, 3);
const numericPrices = products.map((product) => product.price_etb).filter((value) => Number.isFinite(value));
const priceRange = numericPrices.length > 0 ? { min: Math.min(...numericPrices), max: Math.max(...numericPrices) } : null;
let result_type = 'no_match';
let next_step = 'ask_clarification';
let exchange_context = null;

if (rules_output.reply_mode === 'clarify_reference') {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
} else if (resolverInput.flow === 'exchange') {
  result_type = 'exchange_offer';
  next_step = 'ask_clarification';
  exchange_context = { current_interest: session.flow_context?.buy_flow?.current_interest ?? null, extracted_need: understanding_output.extracted_need ?? null };
} else if (selectedProduct) {
  result_type = 'single_product';
  next_step = 'show_single';
} else if (products.length > 1) {
  result_type = 'multiple_options';
  next_step = 'show_options';
} else if ((resolverInput.missing_fields ?? []).length > 0) {
  result_type = 'clarification_needed';
  next_step = 'ask_clarification';
}

const resolver_output = {
  result_type,
  products,
  exchange_context,
  next_step,
  facts_for_reply: {
    product_found: Boolean(selectedProduct || products.length > 0),
    how_many_options: products.length,
    stock_status: selectedProduct?.stock_status ?? null,
    price_range: priceRange,
  },
};

return [{ json: { event, session, client_config, understanding_output, rules_output, resolver_output } }];

