const session = base.session && typeof base.session === 'object' ? base.session : {};
const client_config = base.client_config && typeof base.client_config === 'object' ? base.client_config : {};
const issues = [];

const parseJsonObject = (value) => {
  if (!value) return null;
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value !== 'string' || !value.trim()) return null;
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
};

const rawResponse = parseJsonObject(payload.choices?.[0]?.message?.content)
  || parseJsonObject(payload.output_text)
  || parseJsonObject(payload.text)
  || parseJsonObject(payload.data)
  || parseJsonObject(payload.result)
  || parseJsonObject(payload);
if (!rawResponse) {
  issues.push('understanding_response_not_parseable');
}

const text = String(event.text ?? '').trim();
const lower = text.toLowerCase();
const hasAny = (tokens) => tokens.some((token) => lower.includes(token));
const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const toStringArray = (value) => Array.isArray(value)
  ? value.filter((item) => typeof item === 'string').map((item) => item.trim()).filter(Boolean)
  : [];
const normalizeEnum = (value, allowed, synonyms, label) => {
  if (value === null && allowed.includes(null)) return null;
  if (typeof value === 'string') {
    const normalized = synonyms[String(value).trim().toLowerCase()] ?? String(value).trim().toLowerCase();
    if (allowed.includes(normalized)) return normalized;
    issues.push(label + '_invalid:' + value);
  }
  return undefined;
};

const greetingSignal = hasAny(['selam', 'hello', 'hi', 'hey', 'good morning', 'good evening']);
const acknowledgmentSignal = hasAny(['ok', 'okay', 'thanks', 'thank you', 'got it', 'noted']);
const offTopicSignal = hasAny(['weather', 'football', 'soccer', 'movie', 'music', 'joke', 'news', 'time', 'sleep']);
const pricingSignal = hasAny(['price', 'how much', 'cost', 'budget', 'last price']);
const stockSignal = hasAny(['available', 'availability', 'in stock', 'stock']);
const exchangeSignal = hasAny(['exchange', 'swap', 'trade', 'trade in']);
const supportSignal = hasAny(['problem', 'issue', 'complaint', 'support', 'help']);
const infoSignal = hasAny(['where', 'location', 'address', 'shop', 'store', 'hours', 'payment', 'warranty', 'delivery', 'policy']);
const productSignal = hasAny(['phone', 'iphone', 'samsung', 'tecno', 'infinix', 'redmi', 'xiaomi', 'pixel', 'model', 'slk', 'buy', 'want']);
const humorousSignal = hasAny(['haha', 'lol', 'lmao']);
const urgentSignal = hasAny(['urgent', 'asap', 'quick', 'immediately']);
const formalSignal = hasAny(['please', 'kindly']);
const negativeSignal = hasAny(['bad', 'terrible', 'angry', 'annoyed']);
